import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import {
  ApplicationTrasnactionResponse,
  ClientTrasnaction,
} from "src/app/views/Models/ClientTransactions/ClientTransaction";
import { Observable } from "rxjs";
import { PostingFinancialTransactions } from "src/app/views/Models/ClientTransactions/PostingFinancialTransactions";
import { TransType } from "src/app/views/Models/ClientTransactions/TransType";

@Injectable({
  providedIn: "root",
})
export class ClientTransactionsService {
  constructor(private env: EnvService, private http: HttpClient) {}

  getClientTransactions = async (
    client_key: string
  ): Promise<ClientTrasnaction[]> => {
    try {
      const response = await this.http
        .post<ClientTrasnaction[]>(
          `${this.env.API_URL}api/ClientTransactions/GetClientTransactions`,
          {
            client_key: client_key,
          }
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching ClientTransactions:", error);
      throw error;
    }
  };
  getClientTransactionByTransCode = async (
    trans_code: number
  ): Promise<ClientTrasnaction> => {
    try {
      const response = await this.http
        .get<ClientTrasnaction>(
          `${this.env.API_URL}api/ClientTransactions/GetClientTransactionByTransCode?trans_code=${trans_code}`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching ClientTransactionByTransCode:", error);
      throw error;
    }
  };
  deleteClientTransaction = async (trans_code: number, uuc: string) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/ClientTransactions/DeleteClientTransaction`,
          {
            trans_code: trans_code,
            uuc: uuc,
          }
        )
        .toPromise();
    } catch (error) {
      console.error("Error fetching deleteClientTransaction:", error);
      throw error;
    }
  };
  insertClientTransaction = async (transaction: any) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/ClientTransactions/InsertClientTransaction`,
          {
            client_key: transaction.clientKey.toString(),
            trans_amount: transaction.transAmount,
            trans_act_date: transaction.transActionDate,
            trans_vouch: transaction.transVouch,
            type_key: transaction.transactionType,
            cur_bank_key: transaction.bankKey,
          }
        )
        .toPromise();
    } catch (error) {
      console.error("Error fetching insertClientTransaction:", error);
      throw error;
    }
  };
  editClientTransaction = async (transaction: any) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/ClientTransactions/EditClientTransaction`,
          {
            trans_code: transaction.transCode,
            trans_amount: transaction.transAmount,
            trans_act_date: transaction.transActionDate,
            trans_vouch: transaction.transVouch,
            type_key: transaction.transactionType,
            cur_bank_key: transaction.bankKey,
            uuc: transaction.uuc,
          }
        )
        .toPromise();
    } catch (error) {
      console.error("Error fetching editClientTransaction:", error);
      throw error;
    }
  };

  GetTransType = (
    transType: number,
    cancel: number
  ): Observable<TransType[]> => {
    try {
      return this.http.get<TransType[]>(
        this.env.API_URL +
          `api/ClientTransactions/GetTransTypes?transType=${transType}&cancel=${cancel}`
      );
    } catch (error) {
      console.error("Error GetTransTypes:", error);
      throw error;
    }
  };

  GetFinancialTransactions = (
    transType: number,
    typeKeys: string
  ): Observable<PostingFinancialTransactions[]> => {
    try {
      return this.http.get<PostingFinancialTransactions[]>(
        this.env.API_URL +
          `api/ClientTransactions/GetFinancialTransactions?transType=${transType}&typeKeys=${typeKeys}`
      );
    } catch (error) {
      console.error("Error GetFinancialTransactions:", error);
      throw error;
    }
  };

  postFinancialTransactions = (request: PostingFinancialTransactions[]) => {
    try {
      return this.http.post(
        this.env.API_URL + `api/ClientTransactions/PostFinancialTransactions`,
        request
      );
    } catch (error) {
      console.error("Error PostFinancialTransactions:", error);
      throw error;
    }
  };
  getApplicationTransactions = async (
    client_key: string
  ): Promise<ApplicationTrasnactionResponse[]> => {
    try {
      const response = await this.http
        .post<ApplicationTrasnactionResponse[]>(
          `${this.env.API_URL}api/ClientTransactions/GetApplicationTransactions`,
          {
            client_key: client_key,
          }
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching ApplicationTransactions:", error);
      throw error;
    }
  };
  getApplicationTransactionByTransCode = async (
    trans_code: number
  ): Promise<ApplicationTrasnactionResponse> => {
    try {
      const response = await this.http
        .get<ApplicationTrasnactionResponse>(
          `${this.env.API_URL}api/ClientTransactions/GetApplicationTransactionByTransCode?trans_code=${trans_code}`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching ApplicationTransactionByTransCode:", error);
      throw error;
    }
  };
  insertLoanApplicationTransaction = async (transaction: any) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/ClientTransactions/InsertLoanApplicationTransaction`,
          {
            client_key: transaction.clientKey.toString(),
            trans_amount: transaction.transactionAmount,
            trans_act_date: transaction.transactionMaturityDate,
            trans_vouch: transaction.transactionVoucher,
            type_key: transaction.transactionType,
            application_key: transaction.applicationKey.toString(),
            cur_bank_key: transaction.transactionBank,
          }
        )
        .toPromise();
    } catch (error) {
      console.error("Error fetching insertLoanApplicationTransaction:", error);
      throw error;
    }
  };
}
